import { GoogleGenAI } from "@google/genai";
import { SearchResult, GroundingSource } from "./types";

export const performArchivesSearch = async (query: string): Promise<SearchResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Search for verifiable historical records, archives, and reputable databases regarding: ${query}. Focus on missing children archives, orphanage ledgers, and commercial-related orphan records if applicable. Provide links to the specific databases or reference points.`,
      config: {
        tools: [{ googleSearch: {} }],
        temperature: 0.1, // Low temperature for factual accuracy
      },
    });

    const text = response.text || "No detailed information found.";

    // Extract sources from grounding chunks
    const sources: GroundingSource[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web?.uri && chunk.web?.title) {
          sources.push({
            title: chunk.web.title,
            uri: chunk.web.uri
          });
        }
      });
    }

    return { text, sources };
  } catch (error) {
    console.error("Search failed:", error);
    throw new Error("Failed to connect to the knowledge archives. Please try again.");
  }
};

