import React, { useState, useCallback } from 'react';
import { Layout } from './components/Layout';
import { performAdvancedArchivesSearch, analyzeGeneticMarkers } from './geminiService';
import { SearchResult, SearchFilters } from './types';
import { ADOPTION_SIGNS, REPUTABLE_RESOURCES } from './constants';
import { 
  Search, 
  BookOpen, 
  Link as LinkIcon, 
  ShieldCheck, 
  HelpCircle, 
  AlertCircle,
  ExternalLink,
  ChevronRight,
  Info,
  Calendar,
  MapPin,
  Filter,
  Dna,
  UserCheck
} from 'lucide-react';

const App: React.FC = () => {
  // Archive Search State
  const [keyword, setKeyword] = useState('');
  const [filters, setFilters] = useState<SearchFilters>({
    recordType: ['all'],
  });
  const [searchResult, setSearchResult] = useState<SearchResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Genetic Analysis State
  const [snpData, setSnpData] = useState('');
  const [geneticResult, setGeneticResult] = useState<SearchResult | null>(null);
  const [genLoading, setGenLoading] = useState(false);
  const [genError, setGenError] = useState<string | null>(null);

  const toggleRecordType = (type: 'archived' | 'commercial' | 'orphan' | 'all') => {
    setFilters(prev => {
      if (type === 'all') return { ...prev, recordType: ['all'] };
      const current = prev.recordType.filter(t => t !== 'all');
      if (current.includes(type)) {
        const next = current.filter(t => t !== type);
        return { ...prev, recordType: next.length ? next : ['all'] };
      }
      return { ...prev, recordType: [...current, type] };
    });
  };

  const handleSearch = useCallback(async (e: React.FormEvent) => {
    e.preventDefault();
    if (!keyword.trim()) return;

    setLoading(true);
    setError(null);
    try {
      const result = await performAdvancedArchivesSearch(keyword, filters);
      setSearchResult(result);
      const searchSection = document.getElementById('search-results');
      searchSection?.scrollIntoView({ behavior: 'smooth' });
    } catch (err: any) {
      setError(err.message || 'An unexpected error occurred.');
    } finally {
      setLoading(false);
    }
  }, [keyword, filters]);

  const handleGeneticAnalysis = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!snpData.trim()) return;

    setGenLoading(true);
    setGenError(null);
    try {
      const result = await analyzeGeneticMarkers(snpData);
      setGeneticResult(result);
    } catch (err: any) {
      setGenError(err.message);
    } finally {
      setGenLoading(false);
    }
  };

  return (
    <Layout>
      {/* Hero Section */}
      <section className="relative bg-white overflow-hidden py-16 md:py-24 border-b border-slate-100">
        <div className="absolute top-0 right-0 -mr-20 -mt-20 opacity-10">
          <div className="w-96 h-96 rounded-full bg-indigo-600 blur-3xl"></div>
        </div>

        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
          <div className="max-w-3xl">
            <h2 className="serif text-4xl md:text-5xl font-bold text-slate-900 leading-tight mb-6">
              The record of your life <br/>
              <span className="text-indigo-600 italic underline decoration-indigo-200">is your property.</span>
            </h2>
            <p className="text-lg text-slate-600 leading-relaxed mb-8">
              Explore elusive historical archives and biological markers. KinSeeker empowers you to find the 
              reputable information your family may have hidden, from commercial orphans to genetic anomalies.
            </p>
            <div className="flex flex-wrap gap-4">
              <a href="#search" className="px-6 py-3 bg-indigo-600 text-white font-semibold rounded-lg shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all flex items-center">
                Search Engine <ChevronRight className="ml-2 w-4 h-4" />
              </a>
              <a href="#genetics" className="px-6 py-3 bg-indigo-50 text-indigo-700 font-semibold rounded-lg hover:bg-indigo-100 transition-all flex items-center">
                <Dna className="mr-2 w-4 h-4" /> Bio-Marker Analysis
              </a>
            </div>
          </div>
        </div>
      </section>

      {/* Advanced Search Engine */}
      <section id="search" className="py-20 bg-slate-50">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="text-center mb-12">
            <h2 className="serif text-3xl font-bold text-slate-900 mb-2">Archival Discovery Engine</h2>
            <p className="text-slate-500">Search specialized ledgers, orphanage records, and broadcast archives.</p>
          </div>

          <div className="bg-white rounded-3xl shadow-xl border border-slate-200 overflow-hidden">
            <form onSubmit={handleSearch} className="p-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
                <div className="md:col-span-2">
                  <label className="block text-sm font-bold text-slate-700 mb-2 flex items-center">
                    <Search className="w-4 h-4 mr-2 text-indigo-600" /> Primary Keywords
                  </label>
                  <input
                    type="text"
                    value={keyword}
                    onChange={(e) => setKeyword(e.target.value)}
                    placeholder="e.g., 'St. Vincent Commercial Orphanage', 'Baby Scoop Era 1960 records'"
                    className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2 flex items-center">
                    <MapPin className="w-4 h-4 mr-2 text-indigo-600" /> Location (City/State/Country)
                  </label>
                  <input
                    type="text"
                    value={filters.location || ''}
                    onChange={(e) => setFilters(prev => ({ ...prev, location: e.target.value }))}
                    placeholder="e.g., Chicago, IL"
                    className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2 flex items-center">
                    <Calendar className="w-4 h-4 mr-2 text-indigo-600" /> Date Range / Decade
                  </label>
                  <input
                    type="text"
                    value={filters.dateRange || ''}
                    onChange={(e) => setFilters(prev => ({ ...prev, dateRange: e.target.value }))}
                    placeholder="e.g., 1950 - 1965"
                    className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
              </div>

              <div className="mb-8">
                <label className="block text-sm font-bold text-slate-700 mb-3 flex items-center">
                  <Filter className="w-4 h-4 mr-2 text-indigo-600" /> Advanced Filter Categories
                </label>
                <div className="flex flex-wrap gap-2">
                  {(['all', 'archived', 'commercial', 'orphan'] as const).map(type => (
                    <button
                      key={type}
                      type="button"
                      onClick={() => toggleRecordType(type)}
                      className={`px-4 py-2 rounded-full text-sm font-semibold transition-all border ${
                        filters.recordType.includes(type)
                          ? 'bg-indigo-600 text-white border-indigo-600 shadow-md'
                          : 'bg-white text-slate-600 border-slate-200 hover:border-indigo-300'
                      }`}
                    >
                      {type.charAt(0).toUpperCase() + type.slice(1)} Records
                    </button>
                  ))}
                </div>
              </div>

              <button 
                type="submit"
                disabled={loading}
                className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-indigo-700 transition-all flex items-center justify-center disabled:bg-slate-300"
              >
                {loading ? (
                  <>
                    <div className="animate-spin w-5 h-5 border-2 border-white border-t-transparent rounded-full mr-3"></div>
                    Querying Deep Archives...
                  </>
                ) : 'Execute Deep Search'}
              </button>
            </form>
          </div>

          <div id="search-results" className="mt-12 scroll-mt-24">
            {error && (
              <div className="p-4 bg-red-50 border border-red-100 rounded-2xl text-red-700 flex items-center space-x-3">
                <AlertCircle className="shrink-0 w-5 h-5" />
                <p className="font-medium">{error}</p>
              </div>
            )}

            {searchResult && !loading && (
              <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 space-y-8">
                <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm prose prose-slate max-w-none">
                  <h3 className="text-xl font-bold text-slate-900 mb-4 flex items-center">
                    <BookOpen className="w-5 h-5 mr-2 text-indigo-600" /> Analysis Results
                  </h3>
                  <div className="whitespace-pre-wrap text-slate-700 leading-relaxed text-lg font-light">
                    {searchResult.text}
                  </div>
                </div>

                {searchResult.sources.length > 0 && (
                  <div>
                    <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-4">Verifiable Record Links</h4>
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                      {searchResult.sources.map((source, idx) => (
                        <a 
                          key={idx}
                          href={source.uri}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="flex items-center justify-between p-4 bg-white border border-slate-200 rounded-xl hover:border-indigo-300 hover:shadow-md transition-all group"
                        >
                          <span className="text-sm font-semibold text-slate-800 truncate pr-4">{source.title}</span>
                          <ExternalLink className="w-4 h-4 text-slate-400 group-hover:text-indigo-600 shrink-0" />
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </section>

      {/* Genetic Analysis Section */}
      <section id="genetics" className="py-20 bg-white border-t border-slate-100">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 lg:grid-cols-5 gap-16">
            <div className="lg:col-span-2">
              <div className="sticky top-24">
                <div className="w-16 h-16 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 mb-6">
                  <Dna className="w-8 h-8" />
                </div>
                <h2 className="serif text-3xl font-bold text-slate-900 mb-6">Bio-Marker Insights</h2>
                <p className="text-slate-600 mb-8 leading-relaxed">
                  Enter your SNP data (e.g., from raw DNA files) to identify potential mutations, 
                  biological heritage clues, or intersex markers that may have been concealed in your history.
                </p>
                <div className="space-y-4 text-sm text-slate-500">
                  <div className="flex items-start">
                    <ShieldCheck className="w-4 h-4 mr-2 text-green-600 shrink-0 mt-0.5" />
                    <p>Analysis is grounded in peer-reviewed genomic databases.</p>
                  </div>
                  <div className="flex items-start">
                    <Info className="w-4 h-4 mr-2 text-blue-600 shrink-0 mt-0.5" />
                    <p>Results are educational and not a medical diagnosis.</p>
                  </div>
