            </div>

            <div className="lg:col-span-3">
              <form onSubmit={handleGeneticAnalysis} className="space-y-6">
                <div className="bg-slate-50 p-6 rounded-3xl border border-slate-200">
                  <label className="block text-sm font-bold text-slate-700 mb-3">Input SNPs or Markers</label>
                  <textarea
                    rows={4}
                    value={snpData}
                    onChange={(e) => setSnpData(e.target.value)}
                    placeholder="e.g., rs12345 C T, rs67890 G A..."
