                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                      {geneticResult.sources.map((s, i) => (
                        <a key={i} href={s.uri} target="_blank" className="p-3 bg-white border border-slate-200 rounded-xl text-xs font-semibold text-slate-600 flex items-center justify-between hover:border-indigo-300">
