import { GoogleGenAI } from "@google/genai";
import { SearchResult, GroundingSource, SearchFilters } from "./types";

const aiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const performAdvancedArchivesSearch = async (
  keyword: string, 
  filters: SearchFilters
): Promise<SearchResult> => {
  const ai = aiClient();

  const filterContext = `
    Focus search on these specific record types: ${filters.recordType.join(', ')}.
    ${filters.location ? `Geographic focus: ${filters.location}.` : ''}
    ${filters.dateRange ? `Time period: ${filters.dateRange}.` : ''}
    Special interest: Hard-to-find archived records, children featured in historical commercials/advertisements, and specific orphan asylum ledgers.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Search for verifiable historical records, archives, and reputable databases regarding: "${keyword}". 
      ${filterContext}
      Provide detailed information and direct links to databases or archival entries.`,
      config: {
        tools: [{ googleSearch: {} }],
        temperature: 0.1,
      },
    });

    const text = response.text || "No detailed records found for these criteria.";
    const sources: GroundingSource[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web?.uri && chunk.web?.title) {
          sources.push({ title: chunk.web.title, uri: chunk.web.uri });
        }
      });
    }

    return { text, sources };
  } catch (error) {
    console.error("Advanced search failed:", error);
    throw new Error("The archival connection was interrupted. Please try again.");
  }
};

export const analyzeGeneticMarkers = async (snpData: string): Promise<SearchResult> => {
  const ai = aiClient();

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Analyze the following SNP/Genetic markers for biological insights, focusing on:
      1. Known hereditary mutations or health markers.
      2. Hints at chromosomal variations (e.g., intersex conditions like Klinefelter, Turner, or AIS).
      3. Reputable biological links to ancestry or biological heritage.
      Markers: ${snpData}

      IMPORTANT: Frame the response as helpful, educational, and grounded in published research. Mention specifically that these are 'potential markers' and require professional genetic counseling. List all sources used.`,
      config: {
        tools: [{ googleSearch: {} }],
        temperature: 0.1,
      },
    });

    const text = response.text || "No genetic correlations found for the provided markers.";
    const sources: GroundingSource[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web?.uri && chunk.web?.title) {
          sources.push({ title: chunk.web.title, uri: chunk.web.uri });
        }
      });
    }

    return { text, sources };
