export const comparePhotoWithRecords = async (imageBase64: string, mimeType: string): Promise<SearchResult> => {
  const ai = aiClient();
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        {
          inlineData: {
            data: imageBase64,
            mimeType: mimeType
          }
        },
        {
          text: `Analyze this image against your knowledge of historical missing persons, age-progression techniques, and archival records. 
          Are there notable facial features or markers that align with documented missing child cases or famous unclaimed identities? 
          Provide a comparative analysis and suggest specific databases where similar profiles might be found. 
          Use Google Search to cross-reference current missing person databases if traits look highly specific.
          Frame this as an 'Identity Comparison Analysis' and maintain a respectful, supportive tone.`
        }
      ],
      config: {
        tools: [{ googleSearch: {} }],
        temperature: 0.1,
      },
    });

    const text = response.text || "The visual analysis could not be completed.";
    const sources: GroundingSource[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web?.uri && chunk.web?.title) {
          sources.push({ title: chunk.web.title, uri: chunk.web.uri });
        }
      });
    }

    return { text, sources };
  } catch (error) {
    console.error("Visual comparison failed:", error);
    throw new Error("The visual analysis system encountered an error.");
  }
};

