export const analyzeQuestionProbability = async (userQuestion: string): Promise<QuestionResult> => {
  const ai = aiClient();
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `You are a researcher for KinSeeker, a tool for uncovering hidden adoptions.
      The user is asking: "${userQuestion}".

      Tasks:
      1. Provide a compassionate and factual explanation related to this query in the context of adoption discovery.
      2. Based on historical data, search results, and known anecdotal patterns in the adoption community, estimate the percentage of people with this specific question/concern who eventually discovered they were secretly adopted. 
      3. Use Google Search to find reputable data or similar case studies.

      Format the response as JSON with properties: "text" (string), "percentage" (number, 0-100), "confidence" (string description of the data quality).`,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            text: { type: Type.STRING },
            percentage: { type: Type.NUMBER },
            confidence: { type: Type.STRING }
          },
          required: ["text", "percentage", "confidence"]
        }
      }
    });

    const result = JSON.parse(response.text);
    const sources: GroundingSource[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web?.uri && chunk.web?.title) {
          sources.push({ title: chunk.web.title, uri: chunk.web.uri });
        }
      });
    }

    return { ...result, sources };
  } catch (error) {
    console.error("Question analysis failed:", error);
    throw new Error("Failed to process the question probability analysis.");
  }
};

import React, { useState, useCallback, useRef } from 'react';
import { Layout } from './components/Layout';
import { 
  performAdvancedArchivesSearch, 
  analyzeGeneticMarkers, 
  searchAgeProgressionRecords, 
  comparePhotoWithRecords,
  analyzeQuestionProbability
} from './geminiService';
import { SearchResult, SearchFilters, QuestionResult } from './types';
import { ADOPTION_SIGNS, REPUTABLE_RESOURCES } from './constants';
import { 
  Search, 
  BookOpen, 
  Link as LinkIcon, 
  ShieldCheck, 
  HelpCircle, 
  AlertCircle,
  ExternalLink,
  ChevronRight,
  Info,
  Calendar,
  MapPin,
  Filter,
  Dna,
  UserCheck,
  Camera,
  Upload,
  Image as ImageIcon,
  History,
  MessageSquare,
  BarChart3,
  TrendingUp
} from 'lucide-react';

const App: React.FC = () => {
  // Archive Search State
  const [keyword, setKeyword] = useState('');
  const [filters, setFilters] = useState<SearchFilters>({
    recordType: ['all'],
  });
  const [searchResult, setSearchResult] = useState<SearchResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Genetic Analysis State
  const [snpData, setSnpData] = useState('');
  const [geneticResult, setGeneticResult] = useState<SearchResult | null>(null);
  const [genLoading, setGenLoading] = useState(false);
  const [genError, setGenError] = useState<string | null>(null);

  // Visual Identity State
  const [visualQuery, setVisualQuery] = useState('');
  const [visualResult, setVisualResult] = useState<SearchResult | null>(null);
  const [visualLoading, setVisualLoading] = useState(false);
  const [visualError, setVisualError] = useState<string | null>(null);
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Questions State
  const [userQuestion, setUserQuestion] = useState('');
  const [questionResult, setQuestionResult] = useState<QuestionResult | null>(null);
  const [questionLoading, setQuestionLoading] = useState(false);
  const [questionError, setQuestionError] = useState<string | null>(null);

  const toggleRecordType = (type: 'archived' | 'commercial' | 'orphan' | 'all') => {
    setFilters(prev => {
      if (type === 'all') return { ...prev, recordType: ['all'] };
      const current = prev.recordType.filter(t => t !== 'all');
      if (current.includes(type)) {
        const next = current.filter(t => t !== type);
        return { ...prev, recordType: next.length ? next : ['all'] };
      }
      return { ...prev, recordType: [...current, type] };
    });
  };

  const handleSearch = useCallback(async (e: React.FormEvent) => {
    e.preventDefault();
    if (!keyword.trim()) return;

    setLoading(true);
    setError(null);
    try {
      const result = await performAdvancedArchivesSearch(keyword, filters);
      setSearchResult(result);
      document.getElementById('search-results')?.scrollIntoView({ behavior: 'smooth' });
    } catch (err: any) {
      setError(err.message || 'An unexpected error occurred.');
    } finally {
      setLoading(false);
    }
  }, [keyword, filters]);

  const handleGeneticAnalysis = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!snpData.trim()) return;

    setGenLoading(true);
    setGenError(null);
    try {
      const result = await analyzeGeneticMarkers(snpData);
      setGeneticResult(result);
    } catch (err: any) {
      setGenError(err.message);
    } finally {
      setGenLoading(false);
    }
  };

  const handleVisualSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!visualQuery.trim()) return;
    setVisualLoading(true);
    setVisualError(null);
    try {
      const result = await searchAgeProgressionRecords(visualQuery);
      setVisualResult(result);
    } catch (err: any) {
      setVisualError(err.message);
    } finally {
      setVisualLoading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handlePhotoComparison = async () => {
    if (!uploadedImage) return;
    setVisualLoading(true);
    setVisualError(null);
    try {
      const base64Data = uploadedImage.split(',')[1];
      const mimeType = uploadedImage.split(',')[0].split(':')[1].split(';')[0];
      const result = await comparePhotoWithRecords(base64Data, mimeType);
      setVisualResult(result);
    } catch (err: any) {
      setVisualError(err.message);
    } finally {
      setVisualLoading(false);
    }
  };

  const handleQuestionSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userQuestion.trim()) return;
    setQuestionLoading(true);
    setQuestionError(null);
    try {
      const result = await analyzeQuestionProbability(userQuestion);
      setQuestionResult(result);
    } catch (err: any) {
      setQuestionError(err.message);
    } finally {
      setQuestionLoading(false);
    }
  };

  const scrollToSection = (id: string) => {
    const el = document.getElementById(id);
    if (el) {
      const offset = 80; // height of sticky header
      const bodyRect = document.body.getBoundingClientRect().top;
      const elementRect = el.getBoundingClientRect().top;
      const elementPosition = elementRect - bodyRect;
      const offsetPosition = elementPosition - offset;

